/**
 * EGM96 geoid undulation N (geoid height above the WGS84 ellipsoid), sampled on
 * a 1-degree grid and quantised to centimetres (Int16). Generated from the
 * egm96-universal package (15' EGM96 data) — see scripts note in PR #1355.
 * Used to convert IFC orthometric altitudes to Cesium ellipsoidal heights:
 * ellipsoidal = orthometric + N. 1-degree spacing keeps interpolation error
 * well below 1 m (the geoid is smooth at building scale); this corrects a gross
 * ~40-50 m mis-placement, not a survey-grade transform.
 */
export const EGM96_GRID = {
  latStart: -90, lonStart: -180, step: 1, nLat: 181, nLon: 361,
  /** Int16 centimetres, row-major from (latStart, lonStart), lat ascending, lon ascending. */
  dataB64: '',
} as const;
